import React from 'react';
import { Carousel } from 'antd';

const contentStyle = {
  position: 'relative',
};

const textOverlayStyle = {
  position: 'absolute',
  top: '50%',
  transform: 'translateY(-50%)',
  zIndex: 10,
  textAlign: 'center',
  backgroundColor: 'red',
  width: '100%', // Adjusted width for full width text overlay
};

const imageStyle = {
  width: '100%',
  height: '300px', // Adjusted height
  objectFit: 'cover',
};

const HomeCarousel = () => {
  const calculateLeftPosition = (index, totalSlides) => {
    const centerPosition = 50; // Center position in percentage
    const slideWidth = 100 / totalSlides; // Width of each slide
    const imageWidth = 100; // Assuming images fill the entire width
    const textOverlayWidth = 30; // Estimated width of text overlay in percentage

    // Calculate the left position for the text overlay
    const leftPosition = centerPosition - ((slideWidth - textOverlayWidth) / 2) - ((index + 1) * slideWidth - imageWidth) / 2;

    return leftPosition + '%';
  };

  return (
    <Carousel autoplay style={{ margin: '40px' }}>
      <div style={contentStyle}>
        <img src="/carousel1.avif" alt="Carousel 1" style={imageStyle} />
        <div style={{ ...textOverlayStyle, left: calculateLeftPosition(0, 4) }}>WELCOME SHOP NOW</div>
      </div>
      <div style={contentStyle}>
        <img src="/carousel2.avif" alt="Carousel 2" style={imageStyle} />
        <div style={{ ...textOverlayStyle, left: calculateLeftPosition(1, 4) }}>WELCOME SHOP NOW</div>
      </div>
      <div style={contentStyle}>
        <img src="/carousel3.avif" alt="Carousel 3" style={imageStyle} />
        <div style={{ ...textOverlayStyle, left: calculateLeftPosition(2, 4) }}>WELCOME SHOP NOW</div>
      </div>
      <div style={contentStyle}>
        <img src="/carousel4.avif" alt="Carousel 4" style={imageStyle} />
        <div style={{ ...textOverlayStyle, left: calculateLeftPosition(3, 4) }}>WELCOME SHOP NOW</div>
      </div>
    </Carousel>
  );
};

export default HomeCarousel;
